// Validate input
const body = $json.body || {};
const editalId = body.edital_id;
const tipoAnalise = body.tipo_analise || 'resumo_executivo';

if (!editalId) {
  throw new Error('Missing edital_id in request body');
}

if (!['resumo_executivo', 'habilitacao'].includes(tipoAnalise)) {
  throw new Error('tipo_analise must be resumo_executivo or habilitacao');
}

return [{ json: { edital_id: editalId, tipo_analise: tipoAnalise } }];

// Check if edital was found — v3: includes pncp_detalhes, pncp_itens
const rows = $input.all();
if (!rows.length || !rows[0].json.id) {
  throw new Error('Edital not found in database');
}

const edital = rows[0].json;
const tipoAnalise = $('Validate Input').first().json.tipo_analise;
const contextoEmpresa = $('Validate Input').first().json.contexto_empresa || null;
const hasTexto = edital.texto_completo && edital.texto_completo.length > 100;

return [{ json: {
  edital_id: edital.id,
  pncp_id: edital.pncp_id,
  titulo: edital.titulo,
  objeto: edital.objeto,
  orgao: edital.orgao,
  uf: edital.uf,
  modalidade: edital.modalidade,
  valor_estimado: edital.valor_estimado,
  data_encerramento: edital.data_encerramento,
  url_pncp: edital.url_pncp,
  raw_data: edital.raw_data,
  datajud_orgao: edital.datajud_orgao || null,
  pncp_detalhes: edital.pncp_detalhes || null,
  pncp_itens: edital.pncp_itens || null,
  tipo_analise: tipoAnalise,
  contexto_empresa: contextoEmpresa,
  has_texto_completo: hasTexto,
  texto_completo: hasTexto ? edital.texto_completo : null,
  texto_total_caracteres: edital.texto_total_caracteres || 0
} }];

// After PDF extraction — handle failure gracefully
const extraction = $json;
const editalData = $('Check Edital Data').first().json;

// If extraction failed (neverError means we get error in response body)
if (!extraction.success) {
  // Continue with metadata-only analysis (fallback like v1)
  return [{ json: {
    ...editalData,
    texto_completo: null,
    texto_total_caracteres: 0,
    has_texto_completo: false
  } }];
}

return [{ json: {
  ...editalData,
  texto_completo: extraction.texto_completo,
  texto_total_caracteres: extraction.total_caracteres,
  has_texto_completo: true
} }];

// ============================================================
// PROCESS LLM RESPONSE — v3.1: dynamic cost, modo_analise
// ============================================================
const llmResponse = $json;
// Build Partial Prompt or Build Analysis Prompt may have produced the data
let promptData;
try {
  promptData = $('Build Analysis Prompt').first().json;
} catch(e) {
  try {
    promptData = $('Build Partial Prompt').first().json;
  } catch(e2) {
    promptData = {};
  }
}

const choices = llmResponse.choices || [];
const content = choices.length > 0 ? (choices[0].message?.content || '') : '';
const model = llmResponse.model || promptData.selected_model || 'claude-sonnet-4-5';
const usage = llmResponse.usage || {};
const tokensIn = usage.prompt_tokens || 0;
const tokensOut = usage.completion_tokens || 0;
const tokensTotal = usage.total_tokens || (tokensIn + tokensOut);
const tipoAnalise = promptData.tipo_analise;
const modoAnalise = promptData.modo_analise || 'completo';

// Custo por modelo (USD per 1K tokens)
const COST_MAP = {
  'claude-sonnet-4-5':  { input: 0.003, output: 0.015 },
  'claude-haiku-4-5':   { input: 0.0008, output: 0.004 },
  'claude-opus-4-5':    { input: 0.015, output: 0.075 }
};
const modelBase = Object.keys(COST_MAP).find(k => model.includes(k)) || 'claude-sonnet-4-5';
const costs = COST_MAP[modelBase];
const custoUsd = (tokensIn * costs.input / 1000) + (tokensOut * costs.output / 1000);

if (!content) {
  return [{ json: {
    edital_id: promptData.edital_id,
    status: 'erro',
    resultado: JSON.stringify({
      error: true,
      message: llmResponse.error?.message || 'Empty response from LiteLLM',
      tipo_analise: tipoAnalise
    }),
    model: model,
    tokens: tokensTotal,
    tokens_input: tokensIn,
    tokens_output: tokensOut,
    custo_usd: custoUsd,
    tipo_analise: tipoAnalise,
    has_full_text: promptData.has_full_text || false,
    modo_analise: modoAnalise
  }}];
}

// Build JSONB fragment — Portal reads: resultado.resumo_executivo, resultado.habilitacao, etc.
const jsonbFragment = {};
jsonbFragment[tipoAnalise] = content;
jsonbFragment.tipo_analise = tipoAnalise;
jsonbFragment.versao_prompt = '3.1';
jsonbFragment.modelo_usado = model;
jsonbFragment.modo_analise = modoAnalise;

return [{ json: {
  edital_id: promptData.edital_id,
  pncp_id: promptData.pncp_id,
  status: 'concluida',
  resultado: JSON.stringify(jsonbFragment),
  model: model,
  tokens: tokensTotal,
  tokens_input: tokensIn,
  tokens_output: tokensOut,
  custo_usd: custoUsd,
  tipo_analise: tipoAnalise,
  has_full_text: promptData.has_full_text || false,
  modo_analise: modoAnalise
}}];

// ============================================================
// FORMAT RESPONSE — v3.2: fixes Mode C detection
// In N8N executionOrder v1, $('NodeName').first() on a node
// that did NOT run returns { json: {} } — it does NOT throw.
// So we cannot use try/catch to detect which path ran.
// Instead, check for a sentinel field (edital_id) that is
// always set by both Process LLM Response and Build Insufficient Response.
// ============================================================

let parsed = null;

// Try Process LLM Response (Modes A and B)
const llmData = $('Process LLM Response').first().json;
if (llmData && llmData.edital_id) {
  parsed = llmData;
}

// Fallback: Build Insufficient Response (Mode C)
if (!parsed) {
  const insufficientData = $('Build Insufficient Response').first().json;
  if (insufficientData && insufficientData.edital_id) {
    parsed = insufficientData;
  }
}

// Last resort: empty shell to avoid null errors
if (!parsed) {
  parsed = {};
}

return [{ json: {
  success: parsed.status === 'concluida' || parsed.status === 'insuficiente',
  edital_id: parsed.edital_id,
  tipo_analise: parsed.tipo_analise,
  status: parsed.status,
  modelo: parsed.model,
  tokens_input: parsed.tokens_input || 0,
  tokens_output: parsed.tokens_output || 0,
  custo_usd: parsed.custo_usd || 0.0,
  com_texto_completo: parsed.has_full_text || false,
  modo_analise: parsed.modo_analise || 'unknown',
  versao_prompt: '3.1',
  timestamp: new Date().toISOString()
} }];

// ============================================================
// DETERMINE ANALYSIS MODE — v3.1
// A: texto_completo > 500 chars → full 12-section analysis (Sonnet)
// B: no text but has pncp_itens → partial 5-section (Haiku)
// C: no text, no items → no LLM call, programmatic response
// ============================================================
const edital = $json;

const textoCompleto = edital.texto_completo || '';
const temTexto = textoCompleto.length > 500;

let itens = edital.pncp_itens;
if (typeof itens === 'string') {
  try { itens = JSON.parse(itens); } catch(e) { itens = null; }
}
// Handle paginated: may be array or {data: [...]}
const itensList = Array.isArray(itens) ? itens : (itens && Array.isArray(itens.data) ? itens.data : null);
const temItens = itensList && itensList.length > 0;

let detalhes = edital.pncp_detalhes;
if (typeof detalhes === 'string') {
  try { detalhes = JSON.parse(detalhes); } catch(e) { detalhes = null; }
}

let modo;
if (temTexto) {
  modo = 'completo';
} else if (temItens) {
  modo = 'parcial';
} else {
  modo = 'insuficiente';
}

return [{ json: {
  ...edital,
  modo_analise: modo,
  tem_texto: temTexto,
  has_texto_completo: temTexto,
  tem_itens: temItens,
  pncp_itens_parsed: itensList,
  pncp_detalhes_parsed: detalhes
} }];

// ============================================================
// MODE C — Insufficient data, NO LLM call
// ============================================================
const edital = $json;

return [{ json: {
  edital_id: edital.edital_id,
  pncp_id: edital.pncp_id,
  status: 'insuficiente',
  resultado: JSON.stringify({
    [edital.tipo_analise]: 'Dados insuficientes para análise. Os documentos deste edital não estão disponíveis ou não puderam ser processados. Consulte diretamente no PNCP para baixar os documentos.',
    reason: 'insufficient_data',
    pncp_url: edital.url_pncp || '',
    versao_prompt: '3.1',
    modo_analise: 'insuficiente'
  }),
  model: 'none',
  tokens: 0,
  tokens_input: 0,
  tokens_output: 0,
  custo_usd: 0,
  tipo_analise: edital.tipo_analise,
  has_full_text: false,
  modo_analise: 'insuficiente'
} }];

// ============================================================
// BUILD PARTIAL ANALYSIS PROMPT — Mode B (items + metadata only)
// ============================================================
const edital = $json;
const tipoAnalise = edital.tipo_analise;
const itens = edital.pncp_itens_parsed || [];
const detalhes = edital.pncp_detalhes_parsed || {};

const SYSTEM_BASE = `Você é um analista especializado em contratos e editais de licitação no Brasil, com domínio prático da Lei nº 14.133/2021 e normativos correlatos. Você lê documentos de licitação (editais, termos de referência, anexos, minutas de contrato, erratas, esclarecimentos) e produz análises técnicas estruturadas.

REGRAS INVIOLÁVEIS

1. LITERALIDADE: Relatar apenas o que estiver explicitamente previsto nos documentos fornecidos. Não presumir práticas usuais, interpretações extensivas nem entendimentos implícitos.
2. FONTES EXCLUSIVAS: Basear a análise apenas nos documentos fornecidos pelo usuário. Não usar fontes externas, pesquisas na internet nem conhecimento geral sobre editais.
3. LEITURA INTEGRAL: Ler todos os documentos fornecidos em sua totalidade — capas, índices, quadros, tabelas, notas de rodapé, apêndices, modelos e anexos.
4. AUSÊNCIAS: Se um requisito comumente esperado não for encontrado em nenhum documento, registrá-lo como "não exigido" — sem juízo de valor.
5. CONSOLIDAÇÃO: Se o mesmo requisito aparecer em mais de um ponto, consolidá-lo em um único item. Indicar todas as referências onde ocorre. Destacar diferenças de redação, condições adicionais, exceções ou prazos distintos entre as ocorrências.
6. IMPARCIALIDADE: Não emitir pareceres jurídicos, conclusões subjetivas, recomendações nem opiniões. Limitar-se a descrever e compilar informações.
7. SEM DIVAGAÇÕES: Não incluir saudações, comentários pessoais, menções a "boas práticas", sugestões nem conclusões subjetivas.

FORMATAÇÃO

- Idioma: Português (Brasil), linguagem formal, clara, objetiva.
- Estrutura: Relatório técnico com numeração hierárquica (1., 1.1, 1.1.1). Listas numeradas ou com marcadores. Até 3 níveis de profundidade.
- Títulos: Em MAIÚSCULAS com numeração. Sem sintaxe Markdown (#, ##) nem tags HTML.
- Rastreabilidade: Em cada item relevante, indicar a fonte em itálico: [seção/cláusula, pág. PDF X; pág. interna Y]. Se não houver paginação: [seção/título].
- Listas: Sem tabelas (exceto quando a tarefa solicitar explicitamente). Conteúdo em listas numeradas ou com marcadores.
- Layout: Sem recuos artificiais. Sem separadores visuais (---, _____, *, barras). Separação apenas por numeração e títulos.
- Datas: DD/MM/AAAA HH:MM (Brasília), em ordem cronológica. Converter prazos relativos em datas apenas se todos os elementos estiverem explícitos; caso contrário, manter o prazo relativo e indicar qual elemento falta.
- Valores: R$ 0.000,00 (ponto para milhares, vírgula para decimais).
- Organização: Respeitar as seções definidas pela tarefa. Não repetir conteúdo entre seções. Usar referências cruzadas quando necessário.

TRATAMENTO DE EDGE CASES

- Erratas que contradizem o corpo principal: Registrar ambas as redações, indicar a errata como prevalecente e anotar a contradição.
- Anexos referenciados mas não fornecidos: Registrar como "Anexo [X] referenciado em [localização] — não fornecido para análise".
- Documentos com OCR de baixa qualidade: Se trechos estiverem ilegíveis, indicar "[trecho ilegível em pág. PDF X]".
- Informações conflitantes entre documentos: Registrar ambas as versões com suas respectivas localizações, sem eleger uma como correta.`;

// Format items list
let itensText = '';
if (itens.length > 0) {
  itensText = 'ITENS DA LICITAÇÃO:\n\n';
  for (const item of itens) {
    const sigiloso = item.orcamentoSigiloso;
    const valorUnit = sigiloso ? 'Sigiloso'
      : (item.valorUnitarioEstimado != null
          ? 'R$ ' + Number(item.valorUnitarioEstimado).toLocaleString('pt-BR', {minimumFractionDigits: 2})
          : 'N/I');
    itensText += `- Item ${item.numeroItem}: ${item.descricao || 'N/I'} | Qtd: ${item.quantidade || 'N/I'} ${item.unidadeMedida || ''} | Valor unit.: ${valorUnit} | Critério: ${item.criterioJulgamentoNome || 'N/I'}\n`;
  }
}

const amparoLegalRaw = detalhes.amparoLegal || detalhes.amparoLegalNome || '';
const amparoLegal = typeof amparoLegalRaw === 'object' ? (amparoLegalRaw.nome || '') : amparoLegalRaw;

const srp = detalhes.srp != null ? (detalhes.srp ? 'Sim' : 'Não') : 'N/I';

let valorEstimado = 'Não informado';
if (typeof edital.valor_estimado === 'number' && edital.valor_estimado > 0) {
  valorEstimado = 'R$ ' + edital.valor_estimado.toLocaleString('pt-BR', {minimumFractionDigits: 2});
} else if (detalhes.orcamentoSigilosoDescricao) {
  valorEstimado = detalhes.orcamentoSigilosoDescricao;
}

const userMessage = `TAREFA: ANÁLISE PARCIAL DO EDITAL (baseada em metadados da API PNCP)

AVISO: O texto completo do edital NÃO está disponível. Esta análise é baseada apenas nos dados estruturados da API PNCP (metadados e itens). Gere SOMENTE as 5 seções abaixo — não invente seções adicionais nem tente preencher seções que dependem do texto do edital.

1. INFORMAÇÕES ESSENCIAIS
2. RESUMO EXECUTIVO (parcial — apenas o que os dados estruturados permitem)
3. DETALHAMENTO DO OBJETO (itens da API com quantidades e valores)
10. VALORES (orçamento estimado conforme API — se sigiloso, declarar explicitamente)
12. RISCOS E LIMITAÇÕES DA ANÁLISE — liste as seções não geradas, o que falta para análise completa, e link para documentos no PNCP

Nota: Seções 4, 5, 6, 7, 8, 9, 11 dependem do texto do edital e não serão geradas nesta análise parcial.

---

DADOS DO EDITAL:
- Título: ${edital.titulo || 'N/I'}
- Órgão: ${edital.orgao || 'N/I'} (${edital.uf || 'N/I'})
- Modalidade: ${edital.modalidade || detalhes.modalidadeLicitacaoNome || 'N/I'}
- Modo de Disputa: ${detalhes.modoDisputaNome || 'N/I'}
- Amparo Legal: ${amparoLegal || 'N/I'}
- SRP: ${srp}
- Processo: ${detalhes.processo || 'N/I'}
- Valor Estimado: ${valorEstimado}
- Encerramento: ${edital.data_encerramento || 'N/I'}
- URL: ${edital.url_pncp || 'N/I'}

Descrição do Objeto:
${edital.objeto || 'N/I'}

${itensText}${detalhes.informacaoComplementar ? '\nINFORMAÇÃO COMPLEMENTAR:\n' + detalhes.informacaoComplementar : ''}`;

return [{ json: {
  edital_id: edital.edital_id,
  pncp_id: edital.pncp_id,
  tipo_analise: tipoAnalise,
  system_prompt: SYSTEM_BASE,
  user_message: userMessage,
  selected_model: 'claude-haiku-4-5',
  max_tokens: 4000,
  has_full_text: false,
  texto_chars: userMessage.length,
  modo_analise: 'parcial'
} }];
